#include <bits/stdc++.h>
using namespace std;
const int N=500005;
int n,m,s,f[N][25],dep[N];
vector<int> g[N];
void dfs(int x,int fa)
{
	dep[x]=dep[fa]+1;
	f[x][0]=fa;
	for(int i=0;i<g[x].size();i++)
	{
		int to=g[x][i];
		if(to==fa) continue;
		dfs(to,x);
	}
}
int lca(int x,int y)
{
	if(dep[y]<dep[x]) swap(x,y);
	int k=log2(dep[y])+1;
	for(int i=k;i>=0;i--)
	{
		if((dep[y]-(1<<i))>=dep[x]) y=f[y][i];
	}
	if(x==y) return x;
	for(int i=k;i>=0;i--)
	{
		if(f[x][i]&&f[x][i]!=f[y][i])
		{
			x=f[x][i];
			y=f[y][i];
		}
	}
	return f[x][0];
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>n>>m>>s;
	for(int i=1;i<n;i++)
	{
		int x,y;
		cin>>x>>y;
		g[x].push_back(y);
		g[y].push_back(x);
	}
	dfs(s,0);
	for(int j=1;(1<<j)<=n;j++)
	{
		for(int i=1;i<=n;i++)
		{
			f[i][j]=f[f[i][j-1]][j-1];
		}
	}
	while(m--)
	{
		int x,y;
		cin>>x>>y;
		cout<<lca(x,y)<<'\n';
	}  //上一个 AC 这里多了个 分号
	return 0;
}
